import { DEFAULT_MARKER_COLOR } from '../../../constants.js';
import { SelectionState } from '../../../types/state.js';
import { serializeMarkerRange } from '../../../utils/serialize-marker-range.js';
import {
  AnnotationsIntegrationMarkerConfig,
  AnnotationsIntegrationTrackConfig,
  IndicatorData,
} from '../types.js';
import {
  buildIndicator,
  isAlwaysHidden,
  isAlwaysShown,
  isShownByInteraction,
} from './indicator-visibility-helpers.js';

export const getShownIndicators = (
  tracks: AnnotationsIntegrationTrackConfig[],
  selection: SelectionState,
): IndicatorData[][] =>
  tracks.map(
    (currentTrack: AnnotationsIntegrationTrackConfig, trackIndex) =>
      currentTrack.markers.reduce(
        (
          indicators: IndicatorData[],
          currentMarker: AnnotationsIntegrationMarkerConfig,
        ) => {
          const {
            indicatorsDisplay: trackIndicatorsVisibility,
            color: trackColor,
          } = currentTrack;
          const {
            color: markerColor,
            start: markerStart,
            end: markerEnd,
            indicatorsDisplay: markerIndicatorVisibility,
            priority,
          } = currentMarker;

          if (
            isAlwaysHidden(markerIndicatorVisibility, trackIndicatorsVisibility)
          ) {
            return indicators;
          }

          const markerId = serializeMarkerRange(currentMarker, trackIndex);

          const displayIndicator =
            isAlwaysShown(
              markerIndicatorVisibility,
              trackIndicatorsVisibility,
            ) ||
            isShownByInteraction(
              selection.data,
              markerId,
              markerIndicatorVisibility,
            );

          if (displayIndicator) {
            const color = markerColor ?? trackColor ?? DEFAULT_MARKER_COLOR;
            const indicator = buildIndicator(
              color,
              selection,
              markerId,
              markerStart,
              markerEnd,
              priority,
            );

            return [...indicators, indicator];
          }

          return indicators;
        },
        [] as IndicatorData[],
      ),
    [] as IndicatorData[],
  );
